import { openChromelessWindow } from "../browser.js";
import { getConfig, hasCredentials } from "../config.js";
const UUID_PATTERN = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
export function parseTestRunIds(args) {
    const joined = args.join(",");
    const seen = new Set();
    for (const part of joined.split(",")) {
        const id = part.trim();
        if (id.length > 0 && UUID_PATTERN.test(id)) {
            seen.add(id.toLowerCase());
        }
    }
    return Array.from(seen);
}
export function buildExperimentsUrl(serviceUrl, testRunIds) {
    const url = new URL(`${serviceUrl}/plugin/dataset/experiments`);
    url.searchParams.set("testRunIds", testRunIds.join(","));
    return url.toString();
}
/**
 * Open the experiments viewer in the user's browser, listing the provided
 * test-run IDs side-by-side. Fire-and-forget: there's no handoff back to the
 * CLI — the agent continues with its own evaluation of the replay output
 * while the human reviews the visual diff.
 *
 * Usage: openExperiments <testRunId>[,<testRunId>...] [<testRunId>...]
 */
export async function runOpenExperiments(platform) {
    const args = process.argv.slice(2);
    const testRunIds = parseTestRunIds(args);
    if (testRunIds.length === 0) {
        console.error("Usage: openExperiments <testRunId>[,<testRunId>...] [<testRunId>...]");
        console.error("At least one valid UUID test-run id is required.");
        process.exit(1);
    }
    if (!hasCredentials()) {
        console.error(`Not authenticated. Run ${platform.loginHint} first.`);
        process.exit(1);
    }
    const config = getConfig();
    const url = buildExperimentsUrl(config.serviceUrl, testRunIds);
    console.log(`Opening experiment viewer: ${url}`);
    openChromelessWindow(url);
    process.exit(0);
}
